-- Backfill is10b51Plan — 09.06.2026 (Pakiet 1 fix #0, audyt aff10b5One)
-- Źródło: scripts/audit/aff_flags.csv (audyt 1248 filingów vs SEC EDGAR, doc/AUDIT-10B51-2026-06-09.md)
-- 168 filingów z aff10b5One=1 → ~752 wierszy insider_trades (550 SELL / 139 EXERCISE / 33 TAX / 22 GRANT / 8 OTHER; 0 BUY).
-- Idempotentny. Odwracalność: pre-fix stan = wszystkie false
--   (UPDATE insider_trades SET "is10b51Plan" = false;).
-- Wykonanie: docker compose exec -T postgres psql -U stockpulse -d stockpulse < scripts/db/backfill-10b51-2026-06-09.sql

BEGIN;

CREATE TEMP TABLE plan_acc (accession text PRIMARY KEY);

-- UWAGA (poprawka 10.06.2026): warunek `= false` pomijał 1512 wierszy z NULL
-- (stare kolekcje sprzed defaulta kolumny) — pierwsze wykonanie złapało tylko 488/752.
-- `IS DISTINCT FROM true` obejmuje false ORAZ NULL.
UPDATE insider_trades it
SET "is10b51Plan" = true
FROM plan_acc p
WHERE split_part(it."accessionNumber", '_', 1) = p.accession
  AND it."is10b51Plan" IS DISTINCT FROM true;

-- Sanity: oczekiwane ~752 plan-wierszy, w tym 550 SELL, 0 BUY
SELECT "transactionType", count(*) FILTER (WHERE "is10b51Plan") AS plan_rows, count(*) AS total
FROM insider_trades GROUP BY 1 ORDER BY 1;

COMMIT;

